#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        char *s = (char*)malloc(N + 5);
        scanf("%s", s);
        int *pref = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N; ++i) {
            pref[i+1] = pref[i] + (s[i] == '1');
        }
        int len = N - K + 1; // length of each segment
        int ans = 0;
        for (int i = 0; i < K; ++i) {
            int ones = pref[i + len] - pref[i];
            if (ones & 1) ans++;
        }
        printf("%d\n", ans);
        free(s);
        free(pref);
    }
    return 0;
}

